import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"119. Shift Work Allowance","description":"","frontmatter":{"title":"119. Shift Work Allowance","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","allowances"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/allowances/119-shift-work-allowance.md","filePath":"ebas/mental-health/health-professionals/allowances/119-shift-work-allowance.md"}'),s={name:"ebas/mental-health/health-professionals/allowances/119-shift-work-allowance.md"};function r(l,e,h,i,c,d){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_119-shift-work-allowance" tabindex="-1">119. Shift Work Allowance <a class="header-anchor" href="#_119-shift-work-allowance" aria-label="Permalink to &quot;119. Shift Work Allowance&quot;">​</a></h1><p><strong>119.1</strong> Definitions In this clause 119:</p><p><strong>(a)</strong> Morning shift means any shift that commences between 6:00 p.m. and 6:30 a.m.</p><p><strong>(b)</strong> Afternoon shift means any shift that finishes between 6:00 p.m. and 8:00 a.m.</p><p><strong>(c)</strong> Night shift means any shift that finishes on the day after commencing duty or commences after midnight and before 5:00 a.m.</p><p><strong>(d)</strong> Sunday night shift means a shift worked by a full-time or part-time Employee that commences on Sunday and concludes on Monday.</p><p><strong>(e)</strong> Permanent night shift means an Employee permanently working on any such rostered hours of ordinary night duty for any period in excess of four consecutive weeks.</p><p><strong>119.2</strong> Application Where a shift meets more than one definition as set out in 119.1, the Employee be paid one shift allowance only, with the higher shift allowance where the rates differ.</p><p><strong>119.3</strong> Shift Allowances In addition to any other rates prescribed elsewhere in this Agreement, the Employee will receive the following allowances where an Employee works:</p><p><strong>(a)</strong> A Morning Shift, an allowance set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per rostered period of duty;</p><p><strong>(b)</strong> An Afternoon Shift, an amount set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per rostered period of duty;</p><p><strong>(c)</strong> A Temporary Night Shift</p><p><strong>(i)</strong> In the case of a casual Employee, the amount referred to as the Casual Night Shift Allowance in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per period of duty.</p><p><strong>(ii)</strong> In case of a non casual Employee, the amount referred to in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> as ‘Weekday Night Duty’ for each period of duty commencing on a Monday, Tuesday, Wednesday or Thursday’.</p><p><strong>(iii)</strong> In case of a non casual Employee, the amount referred to in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> as ‘Fri/Sat Night Duty’ for each period of duty commencing on a Friday or Saturday.</p><p><strong>(iv)</strong> In case of a non casual Employee, the amount referred to in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> as ‘Sun Night Duty’ for each period of duty commencing on a Sunday.</p><p><strong>(d)</strong> A Permanent Night Shift</p><p><strong>(i)</strong> In the case of a casual Employee, the amount referred to as the Casual Night Shift Allowance in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> per period of duty.</p><p><strong>(ii)</strong> In case of a non-casual Employee, the amount referred to in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> as ‘Weekday Night Duty’ for each period of duty commencing on a Monday, Tuesday, Wednesday or Thursday’.</p><p><strong>(iii)</strong> In case of a non-casual Employee, the amount referred to in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> as ‘Fri/Sat Night Duty’ for each period of duty commencing on a Friday or Saturday.</p><p><strong>(iv)</strong> In case of a non-casual Employee, the amount referred to in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> as ‘Sun Night Duty’ for each period of duty commencing on a Sunday.</p><p><strong>119.4</strong> Change of shift allowance</p><p><strong>(a)</strong> Provided further that in the case of an Employee who changes from working on one shift to working on another shift the time of commencement of which differs by four hours or more from the first they shall be paid the ‘Change of Shift Allowance’ in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>. applicable to the first year of experience for that Employee on the occasion of each such change in addition to any amount payable under the preceding provisions of this clause.</p><p><strong>(b)</strong> Change of shift allowance is not payable where a single Employee holds two contemporaneous contracted different positions with the same Employer and moving between those positions results in a change of shift pattern which would ordinarily invoke a change of shift allowance payment.</p><p><strong>119.5</strong> The allowances payable pursuant to this clause shall be calculated to the nearest five cents, portions of a cent being disregarded.</p>',25)])])}const m=a(s,[["render",r]]);export{p as __pageData,m as default};
